import {
    ADD_TO_CART_USER,
} from '../_actions/types';

export default function (state = {}, action) {
    switch (action.type) {
        case ADD_TO_CART_USER:
            return {
                ...state, userData: {
                    ...state.userData,
                    cart: action.payload
                }
            }
        default:
            return state;
    }
}
